INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1001, 'Learning complex goals with iterated amplification', 'We’re proposing an AI safety technique called iterated amplification that lets us specify complicated behaviors and goals that are beyond human scale, by demonstrating how to decompose a task into simpler sub-tasks, rather than by providing labeled data or a reward function. Although this idea is in its very early stages and we have only completed experiments on simple toy algorithmic domains, we’ve decided to present it in its preliminary state because we think it could prove to be a scalable a', 'We’re proposing an AI safety technique called iterated amplification that lets us specify complicated behaviors and goals that are beyond human scale, by demonstrating how to decompose a task into simpler sub-tasks, rather than by providing labeled data or a reward function. Although this idea is in its very early stages and we have only completed experiments on simple toy algorithmic domains, we’ve decided to present it in its preliminary state because we think it could prove to be a scalable approach to AI safety.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-complex-goals-with-iterated-amplification', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2018-10-22 07:00:00.000000', '2026-04-07 06:56:48.311954', 'https://openai.com/index/learning-complex-goals-with-iterated-amplification', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1002, 'OpenAI Scholars 2019: Applications open', 'We are now accepting applications for our second cohort of OpenAI Scholars, a program where we provide 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 'We are now accepting applications for our second cohort of OpenAI Scholars, a program where we provide 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2019', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-10-11 07:00:00.000000', '2026-04-07 06:56:48.311964', 'https://openai.com/index/openai-scholars-2019', 0.0, 0);
