INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1006, 'The International 2018: Results', 'OpenAI Five lost two games against top Dota 2 players at The International in Vancouver this week, maintaining a good chance of winning for the first 20–35 minutes of both games.', 'OpenAI Five lost two games against top Dota 2 players at The International in Vancouver this week, maintaining a good chance of winning for the first 20–35 minutes of both games.', 14, 'OpenAI Blog', 'https://openai.com/index/the-international-2018-results', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-08-23 07:00:00.000000', '2026-04-07 06:56:48.312003', 'https://openai.com/index/the-international-2018-results', 0.0, 0);
