INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1028, 'Report from the OpenAI hackathon', 'On March 3rd, we hosted our first hackathon with 100 members of the artificial intelligence community.', 'On March 3rd, we hosted our first hackathon with 100 members of the artificial intelligence community.', 14, 'OpenAI Blog', 'https://openai.com/index/hackathon-follow-up', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-03-15 07:00:00.000000', '2026-04-07 06:56:48.312221', 'https://openai.com/index/hackathon-follow-up', 0.0, 0);
