INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1030, 'On first-order meta-learning algorithms', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/on-first-order-meta-learning-algorithms', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-03-08 08:00:00.000000', '2026-04-07 06:56:48.312240', 'https://openai.com/index/on-first-order-meta-learning-algorithms', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1031, 'Reptile: A scalable meta-learning algorithm', 'We’ve developed a simple meta-learning algorithm called Reptile which works by repeatedly sampling a task, performing stochastic gradient descent on it, and updating the initial parameters towards the final parameters learned on that task. Reptile is the application of the Shortest Descent algorithm to the meta-learning setting, and is mathematically similar to first-order MAML (which is a version of the well-known MAML algorithm) that only needs black-box access to an optimizer such as SGD or A', 'We’ve developed a simple meta-learning algorithm called Reptile which works by repeatedly sampling a task, performing stochastic gradient descent on it, and updating the initial parameters towards the final parameters learned on that task. Reptile is the application of the Shortest Descent algorithm to the meta-learning setting, and is mathematically similar to first-order MAML (which is a version of the well-known MAML algorithm) that only needs black-box access to an optimizer such as SGD or Adam, with similar computational efficiency and performance.', 14, 'OpenAI Blog', 'https://openai.com/index/reptile', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-03-07 08:00:00.000000', '2026-04-07 06:56:48.312250', 'https://openai.com/index/reptile', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1032, 'OpenAI Scholars', 'We’re providing 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 'We’re providing 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-03-06 08:00:00.000000', '2026-04-07 06:56:48.312260', 'https://openai.com/index/openai-scholars', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1033, 'Some considerations on learning to explore via meta-reinforcement learning', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/some-considerations-on-learning-to-explore-via-meta-reinforcement-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-03-03 08:00:00.000000', '2026-04-07 06:56:48.312269', 'https://openai.com/index/some-considerations-on-learning-to-explore-via-meta-reinforcement-learning', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1034, 'Multi-Goal Reinforcement Learning: Challenging robotics environments and request for research', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/multi-goal-reinforcement-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-02-26 08:00:00.000000', '2026-04-07 06:56:48.312279', 'https://openai.com/index/multi-goal-reinforcement-learning', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1035, 'Ingredients for robotics research', 'We’re releasing eight simulated robotics environments and a Baselines implementation of Hindsight Experience Replay, all developed for our research over the past year. We’ve used these environments to train models which work on physical robots. We’re also releasing a set of requests for robotics research.', 'We’re releasing eight simulated robotics environments and a Baselines implementation of Hindsight Experience Replay, all developed for our research over the past year. We’ve used these environments to train models which work on physical robots. We’re also releasing a set of requests for robotics research.', 14, 'OpenAI Blog', 'https://openai.com/index/ingredients-for-robotics-research', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-02-26 08:00:00.000000', '2026-04-07 06:56:48.312290', 'https://openai.com/index/ingredients-for-robotics-research', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1036, 'OpenAI hackathon', 'Come to OpenAI’s office in San Francisco’s Mission District for talks and a hackathon on Saturday, March 3rd.', 'Come to OpenAI’s office in San Francisco’s Mission District for talks and a hackathon on Saturday, March 3rd.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-hackathon', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-02-22 08:00:00.000000', '2026-04-07 06:56:48.312299', 'https://openai.com/index/openai-hackathon', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1037, 'OpenAI supporters', 'We’re excited to welcome new donors to OpenAI.', 'We’re excited to welcome new donors to OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-supporters', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-02-20 08:00:00.000000', '2026-04-07 06:56:48.312319', 'https://openai.com/index/openai-supporters', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1038, 'Preparing for malicious uses of AI', 'We’ve co-authored a paper that forecasts how malicious actors could misuse AI technology, and potential ways we can prevent and mitigate these threats. This paper is the outcome of almost a year of sustained work with our colleagues at the Future of Humanity Institute, the Centre for the Study of Existential Risk, the Center for a New American Security, the Electronic Frontier Foundation, and others.', 'We’ve co-authored a paper that forecasts how malicious actors could misuse AI technology, and potential ways we can prevent and mitigate these threats. This paper is the outcome of almost a year of sustained work with our colleagues at the Future of Humanity Institute, the Centre for the Study of Existential Risk, the Center for a New American Security, the Electronic Frontier Foundation, and others.', 14, 'OpenAI Blog', 'https://openai.com/index/preparing-for-malicious-uses-of-ai', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2018-02-20 08:00:00.000000', '2026-04-07 06:56:48.312309', 'https://openai.com/index/preparing-for-malicious-uses-of-ai', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1039, 'Interpretable machine learning through teaching', 'We’ve designed a method that encourages AIs to teach each other with examples that also make sense to humans. Our approach automatically selects the most informative examples to teach a concept—for instance, the best images to describe the concept of dogs—and experimentally we found our approach to be effective at teaching both AIs', 'We’ve designed a method that encourages AIs to teach each other with examples that also make sense to humans. Our approach automatically selects the most informative examples to teach a concept—for instance, the best images to describe the concept of dogs—and experimentally we found our approach to be effective at teaching both AIs', 14, 'OpenAI Blog', 'https://openai.com/index/interpretable-machine-learning-through-teaching', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-02-15 08:00:00.000000', '2026-04-07 06:56:48.312329', 'https://openai.com/index/interpretable-machine-learning-through-teaching', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1040, 'Discovering types for entity disambiguation', 'We’ve built a system for automatically figuring out which object is meant by a word by having a neural network decide if the word belongs to each of about 100 automatically-discovered “types” (non-exclusive categories).', 'We’ve built a system for automatically figuring out which object is meant by a word by having a neural network decide if the word belongs to each of about 100 automatically-discovered “types” (non-exclusive categories).', 14, 'OpenAI Blog', 'https://openai.com/index/discovering-types-for-entity-disambiguation', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-02-07 08:00:00.000000', '2026-04-07 06:56:48.312339', 'https://openai.com/index/discovering-types-for-entity-disambiguation', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1041, 'Requests for Research 2.0', 'We’re releasing a new batch of seven unsolved problems which have come up in the course of our research at OpenAI.', 'We’re releasing a new batch of seven unsolved problems which have come up in the course of our research at OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/requests-for-research-2', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-01-31 08:00:00.000000', '2026-04-07 06:56:48.312348', 'https://openai.com/index/requests-for-research-2', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1042, 'Scaling Kubernetes to 2,500 nodes', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/scaling-kubernetes-to-2500-nodes', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-01-18 08:00:00.000000', '2026-04-07 06:56:48.312358', 'https://openai.com/index/scaling-kubernetes-to-2500-nodes', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1043, 'Block-sparse GPU kernels', 'We’re releasing highly-optimized GPU kernels for an underexplored class of neural network architectures: networks with block-sparse weights. Depending on the chosen sparsity, these kernels can run orders of magnitude faster than cuBLAS or cuSPARSE. We’ve used them to attain state-of-the-art results in text sentiment analysis and generative modeling of text and images.', 'We’re releasing highly-optimized GPU kernels for an underexplored class of neural network architectures: networks with block-sparse weights. Depending on the chosen sparsity, these kernels can run orders of magnitude faster than cuBLAS or cuSPARSE. We’ve used them to attain state-of-the-art results in text sentiment analysis and generative modeling of text and images.', 14, 'OpenAI Blog', 'https://openai.com/index/block-sparse-gpu-kernels', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-12-06 08:00:00.000000', '2026-04-07 06:56:48.312368', 'https://openai.com/index/block-sparse-gpu-kernels', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1044, 'Learning sparse neural networks through L₀ regularization', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/learning-sparse-neural-networks-through-l0-regularization', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-12-04 08:00:00.000000', '2026-04-07 06:56:48.312377', 'https://openai.com/index/learning-sparse-neural-networks-through-l0-regularization', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1045, 'Interpretable and pedagogical examples', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/interpretable-and-pedagogical-examples', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-11-02 07:00:00.000000', '2026-04-07 06:56:48.312387', 'https://openai.com/index/interpretable-and-pedagogical-examples', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1046, 'Learning a hierarchy', 'We’ve developed a hierarchical reinforcement learning algorithm that learns high-level actions useful for solving a range of tasks, allowing fast solving of tasks requiring thousands of timesteps. Our algorithm, when applied to a set of navigation problems, discovers a set of high-level actions for walking and crawling in different directions, which enables the agent to master new navigation tasks quickly.', 'We’ve developed a hierarchical reinforcement learning algorithm that learns high-level actions useful for solving a range of tasks, allowing fast solving of tasks requiring thousands of timesteps. Our algorithm, when applied to a set of navigation problems, discovers a set of high-level actions for walking and crawling in different directions, which enables the agent to master new navigation tasks quickly.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-a-hierarchy', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-26 07:00:00.000000', '2026-04-07 06:56:48.312397', 'https://openai.com/index/learning-a-hierarchy', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1047, 'Generalizing from simulation', 'Our latest robotics techniques allow robot controllers, trained entirely in simulation and deployed on physical robots, to react to unplanned changes in the environment as they solve simple tasks. That is, we’ve used these techniques to build closed-loop systems rather than open-loop ones as before.', 'Our latest robotics techniques allow robot controllers, trained entirely in simulation and deployed on physical robots, to react to unplanned changes in the environment as they solve simple tasks. That is, we’ve used these techniques to build closed-loop systems rather than open-loop ones as before.', 14, 'OpenAI Blog', 'https://openai.com/index/generalizing-from-simulation', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-19 07:00:00.000000', '2026-04-07 06:56:48.312407', 'https://openai.com/index/generalizing-from-simulation', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1048, 'Sim-to-real transfer of robotic control with dynamics randomization', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/sim-to-real-transfer-of-robotic-control-with-dynamics-randomization', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-18 07:00:00.000000', '2026-04-07 06:56:48.312426', 'https://openai.com/index/sim-to-real-transfer-of-robotic-control-with-dynamics-randomization', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1049, 'Asymmetric actor critic for image-based robot learning', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/asymmetric-actor-critic-for-image-based-robot-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-18 07:00:00.000000', '2026-04-07 06:56:48.312416', 'https://openai.com/index/asymmetric-actor-critic-for-image-based-robot-learning', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1050, 'Domain randomization and generative models for robotic grasping', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/domain-randomization-and-generative-models-for-robotic-grasping', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-17 07:00:00.000000', '2026-04-07 06:56:48.312436', 'https://openai.com/index/domain-randomization-and-generative-models-for-robotic-grasping', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1051, 'Meta-learning for wrestling', 'We show that for the task of simulated robot wrestling, a meta-learning agent can learn to quickly defeat a stronger non-meta-learning agent, and also show that the meta-learning agent can adapt to physical malfunction.', 'We show that for the task of simulated robot wrestling, a meta-learning agent can learn to quickly defeat a stronger non-meta-learning agent, and also show that the meta-learning agent can adapt to physical malfunction.', 14, 'OpenAI Blog', 'https://openai.com/index/meta-learning-for-wrestling', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-11 07:00:00.000000', '2026-04-07 06:56:48.312446', 'https://openai.com/index/meta-learning-for-wrestling', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1052, 'Competitive self-play', 'We’ve found that self-play allows simulated AIs to discover physical skills like tackling, ducking, faking, kicking, catching, and diving for the ball, without explicitly designing an environment with these skills in mind. Self-play ensures that the environment is always the right difficulty for an AI to improve. Taken alongside our Dota 2 self-play results, we have increasing confidence that self-play will be a core part of powerful AI systems in the future.', 'We’ve found that self-play allows simulated AIs to discover physical skills like tackling, ducking, faking, kicking, catching, and diving for the ball, without explicitly designing an environment with these skills in mind. Self-play ensures that the environment is always the right difficulty for an AI to improve. Taken alongside our Dota 2 self-play results, we have increasing confidence that self-play will be a core part of powerful AI systems in the future.', 14, 'OpenAI Blog', 'https://openai.com/index/competitive-self-play', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-10-11 07:00:00.000000', '2026-04-07 06:56:48.312455', 'https://openai.com/index/competitive-self-play', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1053, 'Nonlinear computation in deep linear networks', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/nonlinear-computation-in-deep-linear-networks', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-09-29 07:00:00.000000', '2026-04-07 06:56:48.312465', 'https://openai.com/index/nonlinear-computation-in-deep-linear-networks', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1054, 'Learning to model other minds', 'We’re releasing an algorithm which accounts for the fact that other agents are learning too, and discovers self-interested yet collaborative strategies like tit-for-tat in the iterated prisoner’s dilemma. This algorithm, Learning with Opponent-Learning Awareness (LOLA), is a small step towards agents that model other minds.', 'We’re releasing an algorithm which accounts for the fact that other agents are learning too, and discovers self-interested yet collaborative strategies like tit-for-tat in the iterated prisoner’s dilemma. This algorithm, Learning with Opponent-Learning Awareness (LOLA), is a small step towards agents that model other minds.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-to-model-other-minds', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-09-14 07:00:00.000000', '2026-04-07 06:56:48.312475', 'https://openai.com/index/learning-to-model-other-minds', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1055, 'Learning with opponent-learning awareness', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/learning-with-opponent-learning-awareness', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-09-13 07:00:00.000000', '2026-04-07 06:56:48.312485', 'https://openai.com/index/learning-with-opponent-learning-awareness', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1056, 'OpenAI Baselines: ACKTR & A2C', 'We’re releasing two new OpenAI Baselines implementations: ACKTR and A2C. A2C is a synchronous, deterministic variant of Asynchronous Advantage Actor Critic (A3C) which we’ve found gives equal performance. ACKTR is a more sample-efficient reinforcement learning algorithm than TRPO and A2C, and requires only slightly more computation than A2C per update.', 'We’re releasing two new OpenAI Baselines implementations: ACKTR and A2C. A2C is a synchronous, deterministic variant of Asynchronous Advantage Actor Critic (A3C) which we’ve found gives equal performance. ACKTR is a more sample-efficient reinforcement learning algorithm than TRPO and A2C, and requires only slightly more computation than A2C per update.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-baselines-acktr-a2c', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-08-18 07:00:00.000000', '2026-04-07 06:56:48.312495', 'https://openai.com/index/openai-baselines-acktr-a2c', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1057, 'More on Dota 2', 'Our Dota 2 result shows that self-play can catapult the performance of machine learning systems from far below human level to superhuman, given sufficient compute. In the span of a month, our system went from barely matching a high-ranked player to beating the top pros and has continued to improve since then. Supervised deep learning systems can only be as good as their training datasets, but in self-play systems, the available data improves automatically as the agent gets better.', 'Our Dota 2 result shows that self-play can catapult the performance of machine learning systems from far below human level to superhuman, given sufficient compute. In the span of a month, our system went from barely matching a high-ranked player to beating the top pros and has continued to improve since then. Supervised deep learning systems can only be as good as their training datasets, but in self-play systems, the available data improves automatically as the agent gets better.', 14, 'OpenAI Blog', 'https://openai.com/index/more-on-dota-2', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-08-16 07:00:00.000000', '2026-04-07 06:56:48.312505', 'https://openai.com/index/more-on-dota-2', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1058, 'Dota 2', 'We’ve created a bot which beats the world’s top professionals at 1v1 matches of Dota 2 under standard tournament rules. The bot learned the game from scratch by self-play, and does not use imitation learning or tree search. This is a step towards building AI systems which accomplish well-defined goals in messy, complicated situations involving real humans.', 'We’ve created a bot which beats the world’s top professionals at 1v1 matches of Dota 2 under standard tournament rules. The bot learned the game from scratch by self-play, and does not use imitation learning or tree search. This is a step towards building AI systems which accomplish well-defined goals in messy, complicated situations involving real humans.', 14, 'OpenAI Blog', 'https://openai.com/index/dota-2', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-08-11 07:00:00.000000', '2026-04-07 06:56:48.312515', 'https://openai.com/index/dota-2', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1059, 'Gathering human feedback', 'RL-Teacher is an open-source implementation of our interface to train AIs via occasional human feedback rather than hand-crafted reward functions. The underlying technique was developed as a step towards safe AI systems, but also applies to reinforcement learning problems with rewards that are hard to specify.', 'RL-Teacher is an open-source implementation of our interface to train AIs via occasional human feedback rather than hand-crafted reward functions. The underlying technique was developed as a step towards safe AI systems, but also applies to reinforcement learning problems with rewards that are hard to specify.', 14, 'OpenAI Blog', 'https://openai.com/index/gathering-human-feedback', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-08-03 07:00:00.000000', '2026-04-07 06:56:48.312525', 'https://openai.com/index/gathering-human-feedback', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1060, 'Better exploration with parameter noise', 'We’ve found that adding adaptive noise to the parameters of reinforcement learning algorithms frequently boosts performance. This exploration method is simple to implement and very rarely decreases performance, so it’s worth trying on any problem.', 'We’ve found that adding adaptive noise to the parameters of reinforcement learning algorithms frequently boosts performance. This exploration method is simple to implement and very rarely decreases performance, so it’s worth trying on any problem.', 14, 'OpenAI Blog', 'https://openai.com/index/better-exploration-with-parameter-noise', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-07-27 07:00:00.000000', '2026-04-07 06:56:48.312535', 'https://openai.com/index/better-exploration-with-parameter-noise', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1061, 'Proximal Policy Optimization', 'We’re releasing a new class of reinforcement learning algorithms, Proximal Policy Optimization (PPO), which perform comparably or better than state-of-the-art approaches while being much simpler to implement and tune. PPO has become the default reinforcement learning algorithm at OpenAI because of its ease of use and good performance.', 'We’re releasing a new class of reinforcement learning algorithms, Proximal Policy Optimization (PPO), which perform comparably or better than state-of-the-art approaches while being much simpler to implement and tune. PPO has become the default reinforcement learning algorithm at OpenAI because of its ease of use and good performance.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-baselines-ppo', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-07-20 07:00:00.000000', '2026-04-07 06:56:48.312545', 'https://openai.com/index/openai-baselines-ppo', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1062, 'Robust adversarial inputs', 'We’ve created images that reliably fool neural network classifiers when viewed from varied scales and perspectives. This challenges a claim from last week that self-driving cars would be hard to trick maliciously since they capture images from multiple scales, angles, perspectives, and the like.', 'We’ve created images that reliably fool neural network classifiers when viewed from varied scales and perspectives. This challenges a claim from last week that self-driving cars would be hard to trick maliciously since they capture images from multiple scales, angles, perspectives, and the like.', 14, 'OpenAI Blog', 'https://openai.com/index/robust-adversarial-inputs', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-07-17 07:00:00.000000', '2026-04-07 06:56:48.312554', 'https://openai.com/index/robust-adversarial-inputs', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1063, 'Hindsight Experience Replay', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/hindsight-experience-replay', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-07-05 07:00:00.000000', '2026-04-07 06:56:48.312564', 'https://openai.com/index/hindsight-experience-replay', 0.0, 0);
