INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1074, 'Unsupervised sentiment neuron', 'We’ve developed an unsupervised system which learns an excellent representation of sentiment, despite being trained only to predict the next character in the text of Amazon reviews.', 'We’ve developed an unsupervised system which learns an excellent representation of sentiment, despite being trained only to predict the next character in the text of Amazon reviews.', 14, 'OpenAI Blog', 'https://openai.com/index/unsupervised-sentiment-neuron', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2017-04-06 07:00:00.000000', '2026-04-07 06:56:48.312672', 'https://openai.com/index/unsupervised-sentiment-neuron', 0.0, 0);
