INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1083, 'Attacking machine learning with adversarial examples', 'Adversarial examples are inputs to machine learning models that an attacker has intentionally designed to cause the model to make a mistake; they’re like optical illusions for machines. In this post we’ll show how adversarial examples work across different mediums, and will discuss why securing systems against them can be difficult.', 'Adversarial examples are inputs to machine learning models that an attacker has intentionally designed to cause the model to make a mistake; they’re like optical illusions for machines. In this post we’ll show how adversarial examples work across different mediums, and will discuss why securing systems against them can be difficult.', 14, 'OpenAI Blog', 'https://openai.com/index/attacking-machine-learning-with-adversarial-examples', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2017-02-24 08:00:00.000000', '2026-04-07 06:56:48.312762', 'https://openai.com/index/attacking-machine-learning-with-adversarial-examples', 0.0, 0);
