INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1099, 'Infrastructure for deep learning', 'Deep learning is an empirical science, and the quality of a group’s infrastructure is a multiplier on progress. Fortunately, today’s open-source ecosystem makes it possible for anyone to build great deep learning infrastructure.', 'Deep learning is an empirical science, and the quality of a group’s infrastructure is a multiplier on progress. Fortunately, today’s open-source ecosystem makes it possible for anyone to build great deep learning infrastructure.', 14, 'OpenAI Blog', 'https://openai.com/index/infrastructure-for-deep-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2016-08-29 07:00:00.000000', '2026-04-07 06:56:48.312921', 'https://openai.com/index/infrastructure-for-deep-learning', 0.0, 0);
